import{_ as a,o as i,c as l,ag as o}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"规则编写","description":"","frontmatter":{},"headers":[],"relativePath":"zh/settings/rule-authoring.md","filePath":"zh/settings/rule-authoring.md","lastUpdated":1782660101000}'),t={name:"zh/settings/rule-authoring.md"};function s(d,e,r,c,n,h){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="规则编写" tabindex="-1">规则编写 <a class="header-anchor" href="#规则编写" aria-label="Permalink to &quot;规则编写&quot;">​</a></h1><p>EasyApi 开箱即用地支持标准 HTTP 框架（Spring MVC、WebFlux、JAX-RS、Feign）—— <strong>大多数项目无需自定义规则</strong>。对于扫描器无法察觉的自定义框架行为（例如要求添加请求头的 <code>jakarta.servlet.Filter</code>，或将每个响应包装在信封中的 <code>ResponseBodyAdvice</code>），可使用内置的 AI 助手或外部 skill 来检测并生成规则。完整的规则键目录请参见 <a href="./config-rule">可用配置规则</a>。</p><p>EasyYapi 3.x 提供 <strong>两种方式</strong> 来编写规则。两种方式都写入同一位置——项目级（<code>&lt;project&gt;/.easyapi/</code>）或全局级（<code>~/.easyapi/</code>）的 <code>.easyapi/*.rules</code> 文件。文件夹模型请参见 <a href="./local-file-config">使用项目内配置文件</a>。</p><table tabindex="0"><thead><tr><th>方式</th><th>适用场景</th></tr></thead><tbody><tr><td><a href="#内置-ai-助手">内置 AI 助手</a></td><td>在 IDE 内快速生成；扫描当前项目中隐藏的框架行为</td></tr><tr><td><a href="#外部-easy-yapi-assistant-skill">外部 <code>easy-yapi-assistant</code> skill</a></td><td>从外部 AI 工具（CLI / IDE agent / CI）驱动规则编写；需自行安装该 skill</td></tr></tbody></table><hr><h2 id="内置-ai-助手" tabindex="-1">内置 AI 助手 <a class="header-anchor" href="#内置-ai-助手" aria-label="Permalink to &quot;内置 AI 助手&quot;">​</a></h2><p>EasyYapi 3.0 内置了一个与提供商无关的 AI 助手（基于 LangChain4j），嵌入在 Rules 标签页中。它会读取你现有的规则、用自然语言推理你的请求、提出规则内容，并保存到你选择的 <code>.easyapi/*.rules</code> 文件中。助手<strong>绝不会在未经你明确批准的情况下写入文件</strong>——每个会改变状态的操作都需要点击 Approve。</p><h3 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h3><ol><li>打开 <strong>Settings → EasyApi → AI</strong>（独立的顶级标签页）。</li><li>选择提供商：<code>OPENAI</code>、<code>ANTHROPIC</code>、<code>GEMINI</code>、<code>OLLAMA</code>、<code>AZURE_OPENAI</code> 或 <code>CUSTOM</code>。</li><li>输入 API key（安全存储在 IntelliJ 的 <code>PasswordSafe</code> 中）、base URL（已知提供商会自动填充）和模型名称。</li><li>点击 <strong>Test Connection</strong> 验证。测试使用界面上的字段值，因此你可以在点击 Apply/OK 之前先验证。</li><li>（可选）点击 <strong>Auto-detect</strong>，让 EasyYapi 从环境变量（<code>OPENAI_API_KEY</code>、<code>ANTHROPIC_API_KEY</code>、<code>OLLAMA_HOST</code>……）推断提供商。</li></ol><h3 id="编写规则" tabindex="-1">编写规则 <a class="header-anchor" href="#编写规则" aria-label="Permalink to &quot;编写规则&quot;">​</a></h3><ol><li>打开 <strong>Settings → EasyApi → Rules</strong>。</li><li>点击 <strong>Chat</strong>（底部操作栏）展开内联 AI 面板。</li><li>用自然语言描述你的需求。示例： <ul><li>&quot;将 <code>UserController</code> 中所有端点的名称改为以 <code>fetch_</code> 开头。&quot;</li><li>&quot;给 <code>internal</code> 包下所有类添加标签 <code>internal</code>。&quot;</li><li>&quot;忽略 <code>UserDto</code> 中名为 <code>internalCache</code> 的字段。&quot;</li></ul></li><li>助手会读取你现有的规则（<code>list_rule_keys</code>、<code>get_existing_rules</code>、<code>read_rule_file</code>），推理请求，并提出规则内容。</li><li>在提案卡片中查看。保存前你可以 <strong>Edit</strong> 修改内容。</li><li>点击 <strong>Save…</strong>——选择 Global（<code>~/.easyapi/</code>）或 Project（<code>&lt;project&gt;/.easyapi/</code>）范围 + 文件名。</li><li>规则文件会写入所选文件夹，配置立即重新加载（文件夹是唯一真相来源——无需在设置列表中登记）。</li></ol><h3 id="检测隐藏的框架行为-magic" tabindex="-1">检测隐藏的框架行为（Magic） <a class="header-anchor" href="#检测隐藏的框架行为-magic" aria-label="Permalink to &quot;检测隐藏的框架行为（Magic）&quot;">​</a></h3><p>点击 <strong>Magic</strong>（底部操作栏）而不是 <strong>Chat</strong>，可运行内置的审查与检测指令。Magic 会：</p><ol><li>审查你现有规则的缺口。</li><li>扫描项目中扫描器无法察觉的自定义框架模式——要求添加请求头的 Filter / Interceptor、<code>ResponseBodyAdvice</code> 包装器、<code>HandlerMethodArgumentResolver</code> 注入、元注解、自定义安全注解。</li><li>为每个检测结果提出规则。</li></ol><p>每个提案仍然经过与 Chat 相同的 Approve → Save 流程。写入什么完全由你掌控。</p><h3 id="提示" tabindex="-1">提示 <a class="header-anchor" href="#提示" aria-label="Permalink to &quot;提示&quot;">​</a></h3><ul><li>助手可通过 <code>get_plugin_doc</code> 工具访问插件的知识库，因此它知道完整的规则键目录。</li><li>在提出修改前，可以让它&quot;列出我当前的规则&quot;——有助于了解起始状态。</li><li>助手通过<strong>名称</strong>（如 <code>security.rules</code>）而非绝对路径来定位规则文件。它会根据已跟踪的 <code>.easyapi/</code> 文件夹解析名称。</li></ul><hr><h2 id="外部-easy-yapi-assistant-skill" tabindex="-1">外部 <code>easy-yapi-assistant</code> skill <a class="header-anchor" href="#外部-easy-yapi-assistant-skill" aria-label="Permalink to &quot;外部 `easy-yapi-assistant` skill&quot;">​</a></h2><p>对于从外部 AI 工具驱动规则编写的团队——基于终端的 agent、IDE 助手或 CI 辅助工具——可以安装 <code>easy-yapi-assistant</code> skill。该 skill 使用与 IDE 内助手<strong>相同的知识库</strong>，因此外部工具和内置助手始终基于同一真相来源编写规则。</p><h3 id="该-skill-暴露的内容" tabindex="-1">该 skill 暴露的内容 <a class="header-anchor" href="#该-skill-暴露的内容" aria-label="Permalink to &quot;该 skill 暴露的内容&quot;">​</a></h3><ul><li><strong>规则键目录</strong>——支持规则键及其聚合模式的权威列表。</li><li><strong>自定义模式目录</strong>——Magic 按钮检测的相同模式（Filter / Interceptor / ResponseBodyAdvice / HandlerMethodArgumentResolver / 元注解），每个模式带有检测信号和规则配方。</li><li><strong>辅助脚本</strong>——<code>list_rule_files.sh</code>、<code>read_rule_file.sh</code>、<code>get_existing_rules_for_key.sh</code>，无需打开 IDE 即可检查 <code>.easyapi/</code> 文件夹中的现有规则。</li></ul><h3 id="何时使用该-skill" tabindex="-1">何时使用该 skill <a class="header-anchor" href="#何时使用该-skill" aria-label="Permalink to &quot;何时使用该 skill&quot;">​</a></h3><ul><li>从有文件访问权限但没有 IntelliJ PSI 的终端 AI 工具编写规则。</li><li>在 CI 中跨多个仓库批量检测自定义框架行为。</li><li>生成规则桩，再由人工审查者在 IDE 中定稿。</li><li>当部分团队成员使用 IDE 助手、其他人使用外部工具时，保持规则编写的一致性。</li></ul><h3 id="如何使用" tabindex="-1">如何使用 <a class="header-anchor" href="#如何使用" aria-label="Permalink to &quot;如何使用&quot;">​</a></h3><ol><li><p>全局安装该 skill：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tangcent/easy-yapi</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span></span></code></pre></div><p>这会安装 <code>easy-yapi-assistant</code> skill。安装后，你的 AI 编程助手（Trae、Cursor、Cline、Continue 等）会在你要求添加或修改 EasyApi 规则时自动调用它。</p></li><li><p>在 AI 编程助手中描述你想要的规则——例如&quot;添加一条规则，忽略所有标注了 <code>@Internal</code> 的字段&quot;。助手会使用 skill 捆绑的知识库（规则指南的同步副本）来编写规则。</p></li><li><p>（可选）在提出修改前，使用 skill 的辅助脚本检查 <code>.easyapi/</code> 文件夹的当前状态：</p><ul><li><code>list_rule_files.sh</code>——列出项目/全局 <code>.easyapi/</code> 文件夹中的规则文件。</li><li><code>read_rule_file.sh &lt;name&gt;</code>——读取指定名称的规则文件。</li><li><code>get_existing_rules_for_key.sh &lt;key&gt;</code>——查找给定规则键的现有规则。</li></ul></li><li><p>助手将提议的规则写入项目中的 <code>.easyapi/*.rules</code> 文件（或全局的 <code>~/.easyapi/</code>）。IDE 会在保存时重新加载。</p></li></ol><p>由于 skill 和 IDE 内助手共享同一知识库，一方编写的规则可立即被另一方理解和编辑。</p>',27)])])}const u=a(t,[["render",s]]);export{g as __pageData,u as default};
